(function(){var id='cc-float-frame';var f=document.getElementById(id);if(f){f.remove();return;}var docLink=document.querySelector('a[href*="kdocs.cn/l/"]');var docUrl=docLink?docLink.href.split('?')[0]:'';var docTitle=docLink?docLink.textContent.trim()||document.title:'';f=document.createElement('iframe');f.id=id;f.src='http://localhost:5174/panel?mode=float&docUrl='+encodeURIComponent(docUrl)+'&docTitle='+encodeURIComponent(docTitle);f.allow='clipboard-write';f.style.cssText='position:fixed;right:0;bottom:0;width:480px;height:640px;border:none;z-index:99999;background:transparent;';f.setAttribute('allowtransparency','true');document.body.appendChild(f);})();
